// frontend/src/pages/ProfilePage.js
import { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';

const ProfilePage = () => {
  const { user, setUser } = useAuth();

  const [name, setName] = useState(user?.name || '');
  const [bio, setBio] = useState(user?.bio || '');
  const [pic, setPic] = useState(null);
  const [curPw, setCurPw] = useState('');
  const [newPw, setNewPw] = useState('');
  const [msg, setMsg] = useState('');

  const handleProfile = async (e) => {
    e.preventDefault();
    setMsg('');

    const fd = new FormData();
    fd.append('name', name);
    fd.append('bio', bio);
    if (pic) fd.append('profilePic', pic);

    try {
      const { data } = await API.put('/auth/profile', fd);
      setUser(data);
      setMsg('Profile updated successfully!');
    } catch (err) {
      setMsg(err.response?.data?.message || 'Error updating profile');
    }
  };

  const handlePassword = async (e) => {
    e.preventDefault();
    setMsg('');
    try {
      await API.put('/auth/change-password', {
        currentPassword: curPw,
        newPassword: newPw,
      });
      setMsg('Password changed successfully!');
      setCurPw('');
      setNewPw('');
    } catch (err) {
      setMsg(err.response?.data?.message || 'Error changing password');
    }
  };

  const picSrc = user?.profilePic
    ? `http://localhost:5000/uploads/${user.profilePic}`
    : '/default-avatar.png';

  const styles = {
    page: {
      backgroundColor: '#FAE8ED',
      minHeight: '100vh',
      padding: '30px',
      fontFamily: 'Georgia, serif',
      color: 'rgb(12, 75, 52)',
      display: 'flex',
      justifyContent: 'center',
    },
    container: {
      width: '100%',
      maxWidth: '600px',
      backgroundColor: '#f7c6d9',
      padding: '30px',
      borderRadius: '20px',
      boxShadow: '0 10px 30px rgba(0,0,0,0.1)',
      textAlign: 'center',
    },
    heading: {
      fontSize: '32px',
      marginBottom: '15px',
      fontWeight: 'bold',
    },
    profilePic: {
      width: '120px',
      height: '120px',
      borderRadius: '50%',
      objectFit: 'cover',
      marginBottom: '15px',
      border: '4px solid #fff',
      boxShadow: '0 5px 15px rgba(0,0,0,0.1)',
    },
    message: {
      marginBottom: '15px',
      fontWeight: 'bold',
      color: '#ff4d4d',
    },
    form: {
      display: 'flex',
      flexDirection: 'column',
      gap: '12px',
      marginTop: '15px',
      marginBottom: '25px',
    },
    subHeading: {
      marginTop: '10px',
      marginBottom: '5px',
      fontSize: '18px',
      fontWeight: 'bold',
    },
    input: {
      padding: '12px 18px',
      borderRadius: '50px',
      border: 'none',
      outline: 'none',
      backgroundColor: '#fff',
      fontFamily: 'Georgia, serif',
      fontSize: '14px',
    },
    textarea: {
      padding: '12px 18px',
      borderRadius: '15px',
      border: 'none',
      outline: 'none',
      backgroundColor: '#fff',
      fontFamily: 'Georgia, serif',
      fontSize: '14px',
      resize: 'none',
    },
    fileInput: {
      marginTop: '5px',
    },
    button: {
      padding: '12px',
      borderRadius: '50px',
      border: 'none',
      fontWeight: 'bold',
      cursor: 'pointer',
      backgroundColor: 'rgb(12, 75, 52)',
      color: '#f7c6d9',
      transition: '0.3s',
    },
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h2 style={styles.heading}>My Profile</h2>

        <img src={picSrc} alt='Profile' style={styles.profilePic} />

        {msg && <p style={styles.message}>{msg}</p>}

        {/* Edit Profile */}
        <form style={styles.form} onSubmit={handleProfile}>
          <h3 style={styles.subHeading}>Edit Profile</h3>

          <input
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder='Display name'
            style={styles.input}
          />

          <textarea
            value={bio}
            onChange={(e) => setBio(e.target.value)}
            placeholder='Short bio...'
            rows={3}
            style={styles.textarea}
          />

          <label>Change Profile Picture:</label>
          <input
            type='file'
            accept='image/*'
            onChange={(e) => setPic(e.target.files[0])}
            style={styles.fileInput}
          />

          <button type='submit' style={styles.button}>
            Save Profile
          </button>
        </form>

        {/* Change Password */}
        <form style={styles.form} onSubmit={handlePassword}>
          <h3 style={styles.subHeading}>Change Password</h3>

          <input
            type='password'
            placeholder='Current password'
            value={curPw}
            onChange={(e) => setCurPw(e.target.value)}
            required
            style={styles.input}
          />

          <input
            type='password'
            placeholder='New password (min 6 chars)'
            value={newPw}
            onChange={(e) => setNewPw(e.target.value)}
            required
            minLength={6}
            style={styles.input}
          />

          <button type='submit' style={styles.button}>
            Change Password
          </button>
        </form>
      </div>
    </div>
  );
};

export default ProfilePage;
